import{_ as a,o as t,c as i,ao as n}from"./chunks/framework.P75pzINp.js";const m=JSON.parse('{"title":"Design principles","description":"","frontmatter":{},"headers":[],"relativePath":"principles.md","filePath":"principles.md","lastUpdated":null}'),o={name:"principles.md"};function r(s,e,l,c,d,p){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="Design-principles" tabindex="-1">Design principles <a class="header-anchor" href="#Design-principles" aria-label="Permalink to &quot;Design principles {#Design-principles}&quot;">​</a></h1><p>These are the principles EpiBranch is meant to satisfy. They should be revisited when adding anything substantial, and the architecture should be reviewed against them periodically.</p><h2 id="1.-Simple-but-rigorous" tabindex="-1">1. Simple but rigorous <a class="header-anchor" href="#1.-Simple-but-rigorous" aria-label="Permalink to &quot;1. Simple but rigorous {#1.-Simple-but-rigorous}&quot;">​</a></h2><p>Express what we need, no more. New machinery only earns its place when an analysis we actually do can&#39;t be done without it. Closed-form likelihoods over simulation when both are available and equivalent. One verb (<code>loglikelihood</code>, <code>simulate</code>) does the dispatch — no specialised wrapper functions per data type or model variant.</p><h2 id="2.-Self-explanatory" tabindex="-1">2. Self-explanatory <a class="header-anchor" href="#2.-Self-explanatory" aria-label="Permalink to &quot;2. Self-explanatory {#2.-Self-explanatory}&quot;">​</a></h2><p>Type names, function names, and signatures should match an epidemiologist&#39;s intuition for what they do. If a user has to read source to understand what a public name means, the name is wrong. The mathematical names (<code>Borel</code>, <code>GammaBorel</code>) are fair when they match the literature the user comes from; the operational names should match how an epidemiologist would describe what&#39;s happening.</p><h2 id="3.-Cleanly-separable-concerns" tabindex="-1">3. Cleanly separable concerns <a class="header-anchor" href="#3.-Cleanly-separable-concerns" aria-label="Permalink to &quot;3. Cleanly separable concerns {#3.-Cleanly-separable-concerns}&quot;">​</a></h2><p>Process model, observation model, data, inference, simulation, and output each own one thing. Their interfaces are explicit. New alternatives — network models, multi-stream observation, time-varying reporting, aggregated counts — slot in by implementing the relevant interface, not by editing core code. Each concern is replaceable independently.</p><h2 id="4.-Extensible-from-outside" tabindex="-1">4. Extensible from outside <a class="header-anchor" href="#4.-Extensible-from-outside" aria-label="Permalink to &quot;4. Extensible from outside {#4.-Extensible-from-outside}&quot;">​</a></h2><p>A user can add their own transmission model, observation model, intervention, or data type as a separate package or script, reusing all framework infrastructure. The contracts they have to satisfy are documented and small. Adding a custom piece does not require editing EpiBranch.</p><h2 id="5.-Documented-with-examples" tabindex="-1">5. Documented with examples <a class="header-anchor" href="#5.-Documented-with-examples" aria-label="Permalink to &quot;5. Documented with examples {#5.-Documented-with-examples}&quot;">​</a></h2><p>Principle 4 is empty without 5. Every public extension point has a worked example. Tutorials are checked at build time so the prose stays consistent with the code.</p>',12)])])}const u=a(o,[["render",r]]);export{m as __pageData,u as default};
